VALUES
  ('social-worker-moex-05630', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Kuypers與Benston（1973）提出以社會再建構理論去除老年人負面標籤過程的惡性循環，那一項敘述正確？', '["老年人因生理退化行動不便，故在家安養晚年即可", "社會大眾認為老年人是弱勢族群，故毋須積極社會參與", "發覺使老年人更能控制自我生活的創意方法", "社會應該讓老年人符合不切實際的標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05631', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '針對職業生涯發展的理論，下列敘述何者不適切？', '["決策論主張，以利弊得失及需求滿足之權衡為職業抉擇之基準", "特質因素論基本假定為個人特質與工作要求條件可以相互適配，因此又稱為「適配理論」", "Holland認為生涯選擇係個人在其工作選擇和經驗中，表達自己的個人興趣和價值", "Levinson認為進入職場的歷程必須先發展對該職業認同，並在職場中找到自己的定位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05632', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '自殺死亡率在國內已下降，但仍是一個要關注的議題。下列敘述何者與現實狀況不符合？', '["表達有自殺念頭的女性比率多於男性", "自殺死亡的男性比率多於女性", "2011年起自殺已退出國人十大死因之外", "男性自殺死亡率下降的比率比女性多"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05633', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會環境對人類行為的影響，下列敘述何者正確？', '["各年齡階段受影響的程度各不相同，成年早期剛進入社會，行為受社會環境影響較多", "環境之轉變程度極為重大時 ，個人會自我封閉或產生疏離，個人行為受到的影響較少", "在某一特定的社會環境內，許多人長期的身歷其境、耳濡目染，會形成某些相同或相似的人格特質", "幼年時期由於環境不同，所導致的行為偏差，會形成人格的基礎，以致於終生很難改變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05634', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於行為學派理論內容之描述，下列何者錯誤？', '["著重可觀察、可測量、可記錄的行為", "除了界定出決定行為的產生因素，也關注可能影響行為中無法觀察到的內在因素", "強調環境在產生行為上所扮演的角色", "制約是決定人類行為的基本機制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05635', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '佛洛伊德（Freud）認為人格由本我、自我和超我三部分構成，此概念是：', '["心理分析的內涵", "性心理發展階段", "防衛機轉", "人格結構"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05636', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '社會角色採取的能力（role-taking ability）指的是兒童的發展減少自我中心思考，請問下列那一項陳述正確？', '["能夠以別人的觀點看事情，同理別人的感受", "依據道德原則，扮演好自己角色的能力", "接受別人的指正，願意調整角色的能力", "在別人鼓勵下，可以接受新社會角色的能力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05637', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '許多研究指出母親工作對孩子發展的影響，下列敘述何者正確？', '["職業婦女，特別是成功的職業婦女，通常不是好的母親與妻子", "母親花越多時間和孩子在一起對孩子越好", "職業婦女無法和孩子有強烈的依附關係和情感結合", "有正面的影響，孩子比較獨立與負責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05638', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年加入幫派問題日趨嚴重，Morales（2002）將青少年幫派分成四類：犯罪、衝突、逃避和狂熱，其 中「犯罪型幫派」符合下列那一項陳述？', '["崇敬邪神", "藉由犯罪活動以獲取物資", "地盤勢力取向", "為了取得酒精、古柯鹼、大麻或其他藥物加入幫派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05639', 'social-worker', 'social-worker-moex-105-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Schiller（1995）提出關聯性模式的團體發展，特別適用於女性團體，其發展階段由左至右排列，下列何 者正確？', '["建立初步關係、團體初期、相互同理、挑戰和改變、分離期", "建立初步關係、團體初期、自我揭露、挑戰和改變、分離期", "團體初期、建立初步關係、自我揭露、挑戰和改變、分離期", "團體初期、建立初步關係、相互同理、挑戰和改變、分離期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:31+00:00", "source_pdf_sha1": "622d8515d2b0", "answer_pdf_sha1": "c363cc051cc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "105090", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "105", "exam_name": "105年第二次中醫師分階段營養師心理師護理師社工師暨法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
